  def ui_icon(name, class_name: "ui-icon")
    body = ICONS[name.to_sym]
    return "".html_safe unless body

    content_tag(
      :svg,
      body.html_safe,
      class: class_name,
      xmlns: "http://www.w3.org/2000/svg",
      viewBox: "0 0 16 16",
      fill: "currentColor",
      aria: { hidden: true }
    )
  end
